#include<bits/stdc++.h>
using namespace std;
int a[105][105],n,x,y;
int main(){
    cin>>n>>x>>y;
    for(int i=1;i<=n;i++) for(int j=1;j<=n;j++) a[i][j]=INT_MAX/3;
    for(int i=1;i<=n;i++){
        int k;
        cin>>k;
        for(int j=1;j<=k;j++){
            int xx;
            cin>>xx;
            if(j==1) a[i][xx]=0;
            else a[i][xx]=min(1,a[i][xx]);
        }
    }
    for(int k=1;k<=n;k++) for(int i=1;i<=n;i++) for(int j=1;j<=n;j++) if(a[i][j]>a[i][k]+a[k][j]) a[i][j]=a[i][k]+a[k][j];
    if(a[x][y]==INT_MAX/3) cout<<-1;
    else cout<<a[x][y];
    return 0;
}
